// *highlighted section* Function to generate a complex pattern
void generatePattern(int size) {
    vector<vector<int>> pattern(size, vector<int>(size, 0));
    int center = size / 2;
    int step = 1;

    for (int i = 0; i < size; ++i) {
        for (int j = 0; j < size; ++j) {
            int distance = abs(i - center) + abs(j - center);
            if (distance % 2 == 0) {
                pattern[i][j] = step;
            } else {
                pattern[i][j] = -step;
            }
            step += 1;
        }
    }

    // *highlighted section* Print the pattern
    for (const auto& row : pattern) {
        for (int val : row) {
            cout << setw(4) << val;
        }
        cout << endl;
    }
}

